const item = $input.first();
const inp = item.json || {};
const b = inp.body || inp;

function pick() {
  for (let i = 0; i < arguments.length; i++) {
    const k = arguments[i];
    if (b[k] !== undefined && b[k] !== null && b[k] !== '') return b[k];
  }
  return '';
}
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// Single business -> one fixed Evri claim ceiling (the cap submitted to Evri).
// Client credit = min(cost_value, CEILING); parcel_value submitted = CEILING.
const CEILING = 20;

// Map the n8n Form fields (keys are the field labels) to normalized slugs.
const email = String(pick('customer email address', 'email')).trim().toLowerCase();
let name = String(pick('name', 'customer_name', 'full name')).trim();
if (!name && email) name = email.split('@')[0];
const phone = String(pick('phone number', 'phone', 'phone_number')).trim();
const order_number = String(pick('Order Number', 'order_number')).trim();
const courier = String(pick('Courier', 'courier') || 'Evri').trim();
const claim_raw = String(pick('Claim for Loss or Damage', 'claim_type') || 'Lost');
const claim_type = /damage/i.test(claim_raw) ? 'Damage' : 'Lost'; // form 'Loss' -> Attio 'Lost'
const parcel_count = Number(pick('Number of Parcel Claim', 'parcel_count') || 1);
const tracking_number = String(pick('Tracking Number 1', 'tracking_number')).trim();
const additional_tracking = String(pick('More Tracking Number if any', 'additional_tracking')).trim();
const delivery_postcode = String(pick('Delivery Destination Postcode', 'delivery_postcode', 'postcode')).trim();
const customer_comment = String(pick('What is the reason for your claim?', 'customer_comment', 'comment')).trim();
const cost_value = Number(pick('Cost Value', 'cost_value') || 0);
const parcel_value = CEILING;

const out = { json: {
  correlation_id: uuidv4(),
  email, name, phone,
  courier, claim_type,
  tracking_number, additional_tracking, order_number,
  delivery_postcode, parcel_count, cost_value, parcel_value,
  customer_comment
} };

// Normalize whatever file the form uploaded to binary 'data' for the photo node.
const inb = item.binary || {};
const bk = Object.keys(inb)[0];
if (bk) out.binary = { data: inb[bk] };
return [out];
